import json
lines = open('ios_crash.ips').readlines()
raw = ''.join(lines[1:]).replace('"vmregioninfo"', '"vmregioninfo_lc"')
crash = json.loads(raw)

# Look for termination info, additional ASI, and other clues
for key in ['termination', 'exception', 'extMods', 'asi', 'storeInfo']:
    if key in crash:
        print(f"\n=== {key} ===")
        print(json.dumps(crash[key], indent=2))

# Check all top-level keys
print("\n=== Top-level keys ===")
for k in crash:
    if k not in ['threads', 'usedImages']:
        v = crash[k]
        if isinstance(v, (str, int, float, bool)):
            print(f"  {k}: {v}")
        elif isinstance(v, dict) and len(json.dumps(v)) < 500:
            print(f"  {k}: {json.dumps(v)}")
        elif isinstance(v, list) and len(json.dumps(v)) < 500:
            print(f"  {k}: {json.dumps(v)}")
        else:
            print(f"  {k}: ({type(v).__name__}, len={len(v) if hasattr(v,'__len__') else '?'})")

PYEOF

